from contextlib import contextmanager

class StepBudgetExceeded(Exception): pass

@contextmanager
def with_step_budget(max_steps: int, on_fallback):
    state = {"steps": 0, "tools": [], "t0": time.time()}
    def step(tool_name: str):
        state["steps"] += 1
        state["tools"].append(tool_name)
        if state["steps"] > max_steps:
            log_run(state, status="fallback")
            on_fallback(state)              # hand to human
            raise StepBudgetExceeded()
    try:    yield step
    finally: log_run(state, status=state.get("status", "ok"))

# usage
with with_step_budget(max_steps=12, on_fallback=route_to_cx) as step:
    while not agent.done():
        tool = agent.pick_tool()
        step(tool.name)                     # increments + enforces budget
        agent.run(tool)
